import { Component } from '@angular/core';
import { FormBuilder, FormGroup } from '@angular/forms';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-profile',
  templateUrl: './profile.component.html',
  styleUrls: ['./profile.component.css']
})


export class ProfileComponent {
  form: FormGroup;
  success = '';
  error = '';
  loading = false;

  constructor(private fb: FormBuilder, public authService: AuthService) {
    const u = authService.currentUser!;
    this.form = this.fb.group({
      first_name: [u.first_name],
      last_name: [u.last_name],
      email: [u.email],
      password: [''],
    });
  }

  submit(): void {
    this.loading = true;
    this.success = '';
    this.error = '';
    const data: any = { ...this.form.value };
    if (!data.password) delete data.password;
    this.authService.updateProfile(data).subscribe({
      next: () => {
        this.success = 'Profile updated successfully!';
        this.form.patchValue({ password: '' });
        this.loading = false;
      },
      error: () => {
        this.error = 'Update failed. Please try again.';
        this.loading = false;
      }
    });
  }
}
<div class="container" style="padding-top: 2rem; max-width: 600px">
  <div class="card">
    <h2>My Profile</h2>
    <p class="text-muted">{{ '@' + (authService.currentUser?.username ?? '') }}</p>

    <div class="alert alert-success" *ngIf="success">{{ success }}</div>
    <div class="alert alert-danger" *ngIf="error">{{ error }}</div>

    <form [formGroup]="form" (ngSubmit)="submit()" style="margin-top: 1.5rem">
      <div class="row-2">
        <div class="form-group">
          <label>First Name</label>
          <input class="form-control" formControlName="first_name">
        </div>
        <div class="form-group">
          <label>Last Name</label>
          <input class="form-control" formControlName="last_name">
        </div>
      </div>
      <div class="form-group">
        <label>Email</label>
        <input class="form-control" type="email" formControlName="email">
      </div>
      <div class="form-group">
        <label>New Password <small class="text-muted">(leave blank to keep current)</small></label>
        <input class="form-control" type="password" formControlName="password" placeholder="New password">
      </div>
      <button type="submit" class="btn btn-primary" [disabled]="loading">
        {{ loading ? 'Saving...' : 'Save Changes' }}
      </button>
    </form>
  </div>
</div>
